const yesterday = DateTime.now().setZone('Europe/Moscow').minus({ days: 1 });
const dateStr = yesterday.toFormat('yyyy-MM-dd');
const [year, month, day] = dateStr.split('-').map(Number);
const dateFromRfc = `${dateStr}T00:00:00%2B03:00`;
const dateToRfc = `${dateStr}T23:59:59%2B03:00`;
const pastDate = yesterday.minus({ days: 7 }).toFormat('yyyy-MM-dd');

return [{
  json: {
    date_from: dateStr,
    date_to: dateStr,
    date_from_rfc: dateFromRfc,
    date_to_rfc: dateToRfc,
    past_date: pastDate,
    day,
    month,
    year,
    date_display: yesterday.toFormat('dd.MM')
  }
}];

// WB SuperSale + FitSmile — обработка API и расчёт метрик
const dates = $('Code Dates').first().json;

function processWBCabinet(analytics, advert, statistics) {
  let orderSum = 0, orderCount = 0, buyoutSum = 0, buyoutCount = 0;
  let openCount = 0, cartCount = 0;
  let locWeightedSum = 0, locWeight = 0;
  let ttrWeightedHours = 0, ttrWeight = 0;

  const products = analytics?.products || analytics?.data?.products || [];
  for (const item of products) {
    const stat = item?.statistic?.selected || item?.statistic?.current || item?.statistic || item;
    if (!stat) continue;
    const ordCnt = Number(stat.orderCount) || 0;
    orderSum += Number(stat.orderSum) || 0;
    orderCount += ordCnt;
    buyoutSum += Number(stat.buyoutSum) || 0;
    buyoutCount += Number(stat.buyoutCount) || 0;
    openCount += Number(stat.openCount) || 0;
    cartCount += Number(stat.cartCount) || 0;
    const loc = Number(stat.localizationPercent);
    if (!isNaN(loc) && ordCnt > 0) { locWeightedSum += loc * ordCnt; locWeight += ordCnt; }
    const ttr = stat.timeToReady;
    if (ttr && ordCnt > 0) {
      const d = Number(ttr.days) || 0, h = Number(ttr.hours) || 0, m = Number(ttr.mins) || 0;
      if (h >= 0 && (d > 0 || h > 0 || m > 0)) {
        const totalHours = d * 24 + h + m / 60;
        ttrWeightedHours += totalHours * ordCnt;
        ttrWeight += ordCnt;
      }
    }
  }

  let rashody_reklama = 0;
  const advItems = Array.isArray(advert) ? advert : (advert ? [advert] : []);
  for (const it of advItems) {
    const obj = it?.json ?? it;
    if (Array.isArray(obj)) for (const o of obj) rashody_reklama += Number(o?.updSum) || 0;
    else rashody_reklama += Number(obj?.updSum) || 0;
  }
  rashody_reklama = Math.round(rashody_reklama * 100) / 100;

  let retail_amount = 0, sum_commission = 0, sum_delivery = 0, sum_deduction = 0;
  let sum_storage = 0, sum_penalty = 0, sum_acceptance = 0;
  let buyoutCountFromStats = 0, returnCountFromStats = 0;
  const statItems = Array.isArray(statistics) ? statistics : (statistics ? [statistics] : []);
  for (const it of statItems) {
    const r = it?.json ?? it;
    if (!r) continue;
    const rows = Array.isArray(r) ? r : [r];
    for (const row of rows) {
      const price = Number(row.retail_price_withdisc_rub) || 0;
      const qty = Number(row.quantity) || 0;
      const docType = (row.doc_type_name || '').trim();
      const isSale = docType === 'Продажа';
      const isReturn = docType === 'Возврат';
      if (isSale) buyoutCountFromStats += qty;
      else if (isReturn) returnCountFromStats += qty;
      const amt = price * qty;
      if (isSale) retail_amount += amt;
      else if (isReturn) retail_amount -= amt;
      sum_commission += amt * (Number(row.commission_percent) || 0) / 100;
      sum_delivery += Number(row.delivery_rub) || 0;
      sum_deduction += Number(row.deduction) || 0;
      sum_storage += Number(row.storage_fee) || 0;
      sum_penalty += Number(row.penalty) || 0;
      sum_acceptance += Number(row.acceptance) || 0;
    }
  }

  const avgHours = ttrWeight > 0 ? ttrWeightedHours / ttrWeight : 0;
  const speed_dostavki = ttrWeight > 0 
    ? (avgHours >= 24 ? `${Math.floor(avgHours/24)} д ${Math.round(avgHours % 24)} ч` : `${Math.round(avgHours)} ч`)
    : '';
  const locPct = locWeight > 0 ? Math.min(100, Math.round(locWeightedSum / locWeight)) : '';

  const pct = (v, base) => base > 0 ? Math.round((v / base) * 10000) / 100 : 0;
  const pct_commission = pct(sum_commission, retail_amount);
  const pct_delivery = pct(sum_delivery, retail_amount);
  const pct_deduction = pct(sum_deduction, retail_amount);
  const pct_storage = pct(sum_storage, retail_amount);
  const pct_penalty = pct(sum_penalty, retail_amount);
  const pct_acceptance = pct(sum_acceptance, retail_amount);
  const pct_obshiy = Math.round((pct_commission + pct_delivery + pct_deduction + pct_storage + pct_penalty + pct_acceptance) * 100) / 100;

  return {
    date_display: dates.date_display || '',
    suma_zakazov: orderSum,
    kolvo_tovarov: orderCount,
    vykupili_summa: buyoutCountFromStats > 0 ? Math.round(retail_amount * 100) / 100 : buyoutSum,
    vykupili_tovarov: buyoutCountFromStats > 0 ? Math.max(0, buyoutCountFromStats - returnCountFromStats) : buyoutCount,
    speed_dostavki: speed_dostavki,
    localization_percent: locPct,
    pokazy: openCount,
    pereshli_v_kartochku: openCount,
    polozhili_v_korzinu: cartCount,
    rashody_reklama,
    pct_obshiy,
    pct_commission,
    pct_delivery,
    pct_deduction,
    pct_storage,
    pct_penalty,
    pct_acceptance
  };
}

let superSALE, fitSmile;
try {
  superSALE = processWBCabinet(
    $('Analytics SuperSale').first().json,
    $('Advert SuperSale').all(),
    $('Statistics SuperSale').all()
  );
} catch (e) { superSALE = {}; }
try {
  fitSmile = processWBCabinet(
    $('Analytics FitSmile').first().json,
    $('Advert FitSmile').all(),
    $('Statistics FitSmile').all()
  );
} catch (e) { fitSmile = {}; }

return [{ json: { superSALE: superSALE || {}, fitSmile: fitSmile || {} } }];

// WB SuperSale (243-270) + FitSmile (274-301). Колонка = день месяца.
const merged = $('Code Merge').first().json;
const dates = $('Code Dates').first().json;
const day = Number(dates.day) || 1;
const month = Number(dates.month) || 1;
const year = Number(dates.year) || 2026;
const monthsRu = ['', 'Январь', 'Февраль', 'Март', 'Апрель', 'Май', 'Июнь', 'Июль', 'Август', 'Сентябрь', 'Октябрь', 'Ноябрь', 'Декабрь'];
const sheetName = `${monthsRu[month]}_${String(year).slice(-2)}`;
function colLetter(index) { let letter = ''; let n = index; while (n >= 0) { letter = String.fromCharCode((n % 26) + 65) + letter; n = Math.floor(n / 26) - 1; } return letter; }
const col = colLetter(2 + (day - 1));
const ss = merged.superSALE || {};
const fs = merged.fitSmile || {};
const fmt = (v, pct) => v != null && v !== '' ? (pct ? String(v).replace('.', ',') + '%' : v) : '';
const pctDecimal = (v) => v != null && v !== '' ? Number(v) / 100 : '';

const range1a = `'${sheetName}'!${col}243:${col}250`;
const values1a = [
  [ss.suma_zakazov], [ss.kolvo_tovarov], [ss.vykupili_summa], [ss.vykupili_tovarov],
  [], [],
  [ss.speed_dostavki], [pctDecimal(ss.localization_percent)]
];
const range1b = `'${sheetName}'!${col}252:${col}253`;
const values1b = [
  [ss.pereshli_v_kartochku], [ss.polozhili_v_korzinu]
];
const range2 = `'${sheetName}'!${col}256:${col}256`;
const values2 = [[ss.rashody_reklama]];
const range3 = `'${sheetName}'!${col}264:${col}270`;
const values3 = [
  [fmt(ss.pct_obshiy, 1)], [fmt(ss.pct_commission, 1)], [fmt(ss.pct_delivery, 1)],
  [fmt(ss.pct_deduction, 1)], [fmt(ss.pct_storage, 1)], [fmt(ss.pct_penalty, 1)], [fmt(ss.pct_acceptance, 1)]
];
const range4a = `'${sheetName}'!${col}274:${col}281`;
const values4a = [
  [fs.suma_zakazov], [fs.kolvo_tovarov], [fs.vykupili_summa], [fs.vykupili_tovarov],
  [], [],
  [fs.speed_dostavki], [pctDecimal(fs.localization_percent)]
];
const range4b = `'${sheetName}'!${col}283:${col}284`;
const values4b = [
  [fs.pereshli_v_kartochku], [fs.polozhili_v_korzinu]
];
const range5 = `'${sheetName}'!${col}287:${col}287`;
const values5 = [[fs.rashody_reklama]];
const range6 = `'${sheetName}'!${col}295:${col}301`;
const values6 = [
  [fmt(fs.pct_obshiy, 1)], [fmt(fs.pct_commission, 1)], [fmt(fs.pct_delivery, 1)],
  [fmt(fs.pct_deduction, 1)], [fmt(fs.pct_storage, 1)], [fmt(fs.pct_penalty, 1)], [fmt(fs.pct_acceptance, 1)]
];
const range0 = `'${sheetName}'!${col}1:${col}1`;
const values0 = [[dates.date_display || '']];

return [{ json: { range0, values0, range1a, values1a, range1b, values1b, range2, values2, range3, values3, range4a, values4a, range4b, values4b, range5, values5, range6, values6 } }];
